using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back, optionally uppercased.")]
    public static string Echo(
        [Description("The message to echo")] string message,
        [Description("If true, returns the message in uppercase")] bool uppercase = false)
    {
        return uppercase ? message.ToUpperInvariant() : message;
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { EnableCaching = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/endpoints", Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of available API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Method = "POST", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Method = "GET", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

